tasks.command:
$files = @(
    "src/core/globals.gd", "src/core/globals.gd.uid",
    "src/data/army_obj.gd", "src/data/army_obj.gd.uid",
    "src/data/caravan_obj.gd", "src/data/caravan_obj.gd.uid",
    "src/data/entity_obj.gd", "src/data/entity_obj.gd.uid",
    "src/data/faction_data.gd", "src/data/faction_data.gd.uid",
    "src/data/player_data.gd", "src/data/player_data.gd.uid",
    "src/data/settlement_obj.gd", "src/data/settlement_obj.gd.uid",
    "src/data/unit_obj.gd", "src/data/unit_obj.gd.uid"
)

foreach ($oldRel in $files) {
    $oldPath = "c:\Users\patri\Documents\falling-leaves\" + $oldRel.Replace("/", "\")
    if (Test-Path $oldPath) {
        $dir = Split-Path $oldPath
        $name = Split-Path $oldPath -Leaf
        if ($name -eq "globals.gd") { $newName = "Globals.gd" }
        elseif ($name -eq "globals.gd.uid") { $newName = "Globals.gd.uid" }
        else {
            $newName = (Get-Culture).TextInfo.ToTitleCase($name.Replace("_", " ")).Replace(" ", "")
        }
        $tempPath = $oldPath + ".rename_tmp"
        # Force rename using temp file
        Move-Item -LiteralPath $oldPath -Destination $tempPath -Force
        Move-Item -LiteralPath $tempPath -Destination (Join-Path $dir $newName) -Force
    }
}
